import numpy as np

def compute_scale_zero_point(tensor: np.ndarray, n_bits: int) -> tuple:
    q_max = 2 ** n_bits - 1
    t_min = float(np.min(tensor))
    t_max = float(np.max(tensor))
    scale = (t_max - t_min) / q_max
    if scale == 0:
        scale = 1.0
    zero_point = int(np.clip(np.round(-t_min / scale), 0, q_max))
    return scale, zero_point

def quantize_asymmetric(tensor: np.ndarray, scale: float, zero_point: int, n_bits: int) -> np.ndarray:
    q_max = 2 ** n_bits - 1
    q = np.round(tensor / scale) + zero_point
    return np.clip(q, 0, q_max).astype(np.int32)

def dequantize_asymmetric(q_tensor: np.ndarray, scale: float, zero_point: int) -> np.ndarray:
    return (q_tensor.astype(np.float32) - zero_point) * scale
